<?phpnamespace App\Http\Middleware;use Closure;use Illuminate\Http\Request;use Illuminate\Support\Facades\App;use Illuminate\Support\Facades\Session;use Illuminate\Support\Facades\Log;class Localization{    public function handle(Request $request, Closure $next)    {        // Default locale        $locale = 'en';                // Check session first (most reliable)        if (Session::has('locale')) {            $locale = Session::get('locale');        }        // Then check cookie        elseif ($request->cookie('locale')) {            $locale = $request->cookie('locale');            Session::put('locale', $locale);        }                // Make sure locale is valid        if (!in_array($locale, ['en', 'km'])) {            $locale = 'en';            Session::put('locale', $locale);        }                // Set the locale        App::setLocale($locale);                // Log for debugging        Log::info('Localization middleware running', [            'session_locale' => Session::get('locale'),            'cookie_locale' => $request->cookie('locale'),            'final_locale' => $locale,            'app_locale' => App::getLocale(),            'url' => $request->url()        ]);                return $next($request);    }} 